Vtiger_BaseValidator_Js("Vtiger_PhoneValidator_Js",{},{error:"",validate:function(){var r=this.fieldInfo.val(),e=r.replace(/[\(\)\.\-\ ]/g,"");""==r?this.getEmptyPhoneNumberError():isNaN(parseInt(e))?this.getPhoneNumberIllegalCharacterError():10!==e.length&&this.getPhoneNumberWrongLengthError()},getEmptyPhoneNumberError:function(){return this.error="You didn't enter a phone number.\n",this.error},getPhoneNumberIllegalCharacterError:function(){return this.error="The phone number contains illegal characters.\n",this.error},getPhoneNumberWrongLengthError:function(){return this.error="The phone number is the wrong length. Make sure you included an area code.\n",this.error}});